import os, time, html

def _fmt(seconds):
    if seconds is None: return ''
    m, s = divmod(int(seconds), 60)
    ms = int((seconds - int(seconds)) * 100)
    return f'{m}:{s:02d}.{ms:02d}'

def generate_html_report(diffs, summary, audio_text, doc_text, audio_path=None, output_dir=None):
    if output_dir is None:
        output_dir = os.path.join(os.path.expanduser('~'), 'Desktop')

    doc_paragraphs = [p.strip() for p in doc_text.split('\n') if p.strip()]

    # Build annotated paragraphs
    diff_by_pos = {}
    for d in diffs:
        diff_by_pos.setdefault(d.get('position', 0), []).append(d)

    annotated = []
    for idx, para in enumerate(doc_paragraphs):
        if idx not in diff_by_pos:
            annotated.append(html.escape(para))
            continue

        para_diffs = diff_by_pos[idx]
        located = []
        used = set()
        for d in para_diffs:
            dt = d.get('docText', '')
            if d.get('type') == 'extra_in_audio' or not dt:
                located.append((len(para), len(para), d))
                continue
            start = 0
            while True:
                pos = para.find(dt, start)
                if pos == -1:
                    located.append((len(para), len(para), d))
                    break
                if pos not in used:
                    used.add(pos)
                    located.append((pos, pos + len(dt), d))
                    break
                start = pos + 1
        located.sort(key=lambda x: x[0])

        parts = []
        cursor = 0
        for start, end, d in located:
            dtype = d.get('type', 'mismatch')
            at = html.escape(d.get('audioText', ''))
            ts = _fmt(d.get('time_start'))
            uncertain = ' uncertain' if d.get('uncertain') else ''
            ts_attr = f' data-time="{d["time_start"]}"' if d.get('time_start') is not None else ''
            ts_label = f' <span class="ts">@{ts}</span>' if ts else ''

            if start > cursor:
                parts.append(html.escape(para[cursor:start]))

            if dtype == 'mismatch':
                parts.append(f'<span class="diff mismatch{uncertain}"{ts_attr}>{html.escape(para[start:end])}'
                             f'<span class="note">[误读为:"{at}"{ts_label}]</span></span>')
            elif dtype == 'missing_in_audio':
                parts.append(f'<span class="diff missing{uncertain}"{ts_attr}>{html.escape(para[start:end])}'
                             f'<span class="note">[漏读{ts_label}]</span></span>')
            elif dtype == 'extra_in_audio':
                parts.append(f'<span class="diff extra{uncertain}"{ts_attr}>'
                             f'<span class="note">[多读:"{at}"{ts_label}]</span></span>')
            cursor = end

        if cursor < len(para):
            parts.append(html.escape(para[cursor:]))
        annotated.append(''.join(parts))

    audio_tag = ''
    if audio_path and os.path.exists(audio_path):
        audio_tag = f'<audio id="player" controls src="file:///{audio_path.replace(os.sep, "/")}"></audio>'

    body = '\n'.join(f'<p>{a}</p>' for a in annotated)
    summary_html = html.escape(summary).replace('\n', '<br>')

    content = f'''<!DOCTYPE html>
<html lang="zh"><head><meta charset="utf-8"><title>配音对比报告</title>
<style>
body {{ font-family: "Microsoft YaHei", sans-serif; max-width: 900px; margin: 40px auto; padding: 0 20px; line-height: 1.8; background: linear-gradient(135deg, #FFF8DC, #FFDAB9, #FFE4B5, #FFEFD5); }}
.summary {{ background: linear-gradient(90deg, #FFE4B5, #FFDAB9); padding: 20px; border-radius: 8px; margin-bottom: 24px; font-size: 19px; border-left: 4px solid #FF6B6B; box-shadow: 0 2px 8px rgba(255,107,107,0.2); }}
.diff {{ position: relative; cursor: pointer; }}
.mismatch {{ color: #d32f2f; font-weight: bold; text-decoration: underline; }}
.missing {{ color: #d32f2f; font-weight: bold; text-decoration: line-through; }}
.extra {{ color: #e65100; }}
.uncertain {{ opacity: 0.6; font-style: italic; }}
.note {{ font-size: 15px; font-weight: bold; color: #d32f2f; }}
.ts {{ color: #0066cc; font-size: 14px; font-weight: bold; }}
p {{ margin: 8px 0; font-size: 20px; }}
audio {{ width: 100%; margin-bottom: 16px; }}
.legend {{ display: flex; gap: 20px; margin-bottom: 16px; font-size: 16px; background: linear-gradient(90deg, #FFE4B5, #FFDAB9, #FFB347); padding: 12px 16px; border-radius: 8px; box-shadow: 0 2px 6px rgba(255,107,107,0.15); }}
.legend span {{ padding: 4px 10px; border-radius: 4px; }}
h2 {{ color: #FF6B6B; text-shadow: 1px 1px 2px rgba(255,107,107,0.3); }}
</style></head><body>
<h2>🍉 配音质量核查报告 🍊</h2>
<div class="summary">{summary_html}</div>
<div class="legend">
<span class="mismatch">误读</span>
<span class="missing">漏读</span>
<span style="color:#e65100">多读</span>
</div>
{audio_tag}
<div id="content">{body}</div>
<script>
document.querySelectorAll('.diff[data-time]').forEach(el => {{
  el.addEventListener('click', () => {{
    const player = document.getElementById('player');
    if (player) {{ player.currentTime = parseFloat(el.dataset.time); player.play(); }}
  }});
}});
</script>
<footer style="text-align:center;color:#FF6B6B;padding:20px;font-size:16px;font-weight:bold;">🍓 单夫纯制作，保留权利 🍋</footer>
</body></html>'''

    ts = time.strftime('%Y%m%d_%H%M%S')
    path = os.path.join(output_dir, f'对比报告_{ts}.html')
    with open(path, 'w', encoding='utf-8') as f:
        f.write(content)
    return path

import requests, json, re
import jieba
from difflib import SequenceMatcher
from jiwer import wer, cer
from pypinyin import pinyin, Style
from functools import lru_cache
from typing import List, Tuple, Dict, Any

FILLER_WORDS = {'嗯', '呃', '啊', '哦', '呢', '吧', '嘛', '哈', '噢', '诶',
                '那个', '就是', '就是说', '然后', '对吧', '对的', '这个',
                '那', '所以', '但是', '不过', '其实', '反正', '好的'}

# 中文数字映射
CN_NUMBERS = {
    '零': '0', '〇': '0', '一': '1', '二': '2', '两': '2', '三': '3', '四': '4',
    '五': '5', '六': '6', '七': '7', '八': '8', '九': '9', '十': '10',
    '廿': '20', '卅': '30', '卌': '40', '百': '100', '千': '1000',
    '万': '10000', '亿': '100000000', '兆': '1000000000000'
}
CN_NUMBERS_READING = {
    '0': '零', '1': '一', '2': '二', '3': '三', '4': '四',
    '5': '五', '6': '六', '7': '七', '8': '八', '9': '九'
}

# ===== 性能优化：预编译正则表达式 =====
_RE_PUNCT = re.compile(r'[，。！？；：、\u201c\u201d\u2018\u2019（）【】《》…—·\s,.!?;:\'"()\[\]{}\-]')
_RE_PUNCT_SIMPLE = re.compile(r'[，。！？；：、\u201c\u201d\u2018\u2019（）【】《》…—·\s,.!?;:\'"()\[\]{}\-]')
_RE_YEAR = re.compile(r'(\d{4})年')
_RE_PERCENT_RANGE = re.compile(r'(\d+)%-(\d+)%')
_RE_PERCENT = re.compile(r'(\d+)%')
_RE_RANGE = re.compile(r'(\d+)-(\d+)(年|月|日|元|美元|亿|万|)?')
_RE_WITH_UNIT = re.compile(r'(\d+)([亿万千百元块美])')
_RE_NUMBER = re.compile(r'\b(\d+)\b')
_RE_WHITESPACE = re.compile(r'\s+')

# 句子结束标点集合（用于快速检查）
_SENTENCE_END_PUNCT = set('。！？.!?\n')

# ===== 性能优化：jieba分词器复用 =====
_jieba_initialized = False

def _ensure_jieba_initialized():
    """确保jieba分词器只初始化一次"""
    global _jieba_initialized
    if not _jieba_initialized:
        jieba.initialize()
        _jieba_initialized = True

# ===== 性能优化：拼音缓存 =====
@lru_cache(maxsize=10000)
def _get_char_pinyin(char: str) -> List[str]:
    """获取单个字符的拼音（带缓存）"""
    if not char:
        return []
    return pinyin(char, style=Style.TONE3, neutral_tone_with_five=True)[0]

# ===== 性能优化：批量拼音计算 =====
def _get_pinyin_batch(text: str) -> List[List[str]]:
    """批量计算拼音，减少函数调用开销"""
    return [_get_char_pinyin(c) for c in text]

# ===== 性能优化：标点符号快速判断 =====
def _is_punct(ch: str) -> bool:
    """快速判断是否为标点符号（使用预编译正则和集合查找）"""
    if len(ch) == 1:
        # ASCII标点快速路径
        if ch in '.,!?;:\'"()[]{}-\n\r\t ':
            return True
    return _RE_PUNCT_SIMPLE.match(ch) is not None

# ===== 性能优化：jieba分词器复用 =====
_jieba_initialized = False

def _ensure_jieba_initialized():
    """确保jieba分词器只初始化一次"""
    global _jieba_initialized
    if not _jieba_initialized:
        jieba.initialize()
        _jieba_initialized = True

# ===== 性能优化：拼音缓存 =====
@lru_cache(maxsize=10000)
def _get_char_pinyin(char: str) -> List[str]:
    """获取单个字符的拼音（带缓存）"""
    if not char:
        return []
    return pinyin(char, style=Style.TONE3, neutral_tone_with_five=True)[0]

def _arabic_to_chinese_simple(num_str, is_year=False):
    """将阿拉伯数字字符串转换为中文读音形式

    Args:
        num_str: 阿拉伯数字字符串，如 "15"
        is_year: 是否为年份（年份逐位读：2023→二零二三，普通数字整体读：15→十五）

    Returns:
        中文读音，如 "十五" 或 "二零二三"
    """
    if not num_str or not num_str.isdigit():
        return num_str

    # 年份：逐位读法
    if is_year:
        return ''.join(CN_NUMBERS_READING.get(d, d) for d in num_str)

    # 普通数字：完整读法
    try:
        num = int(num_str)
        if num < 10:
            return CN_NUMBERS_READING[num_str]
        elif num < 20:
            return '十' + (CN_NUMBERS_READING[num_str[1]] if num_str[1] != '0' else '')
        elif num < 100:
            tens = num // 10
            ones = num % 10
            result = CN_NUMBERS_READING[str(tens)] + '十' if tens != 1 else '十'
            if ones > 0:
                result += CN_NUMBERS_READING[str(ones)]
            return result
        elif num < 1000:
            hundreds = num // 100
            remainder = num % 100
            result = CN_NUMBERS_READING[str(hundreds)] + '百'
            if remainder > 0:
                if remainder < 10:
                    result += '零' + CN_NUMBERS_READING[str(remainder)]
                elif remainder < 20:
                    result += '一十'
                    if remainder > 10:
                        result += CN_NUMBERS_READING[str(remainder % 10)]
                else:
                    result += _arabic_to_chinese_simple(str(remainder))
            return result
        elif num < 10000:
            thousands = num // 1000
            remainder = num % 1000
            result = CN_NUMBERS_READING[str(thousands)] + '千'
            if remainder > 0 and remainder < 100:
                result += '零' + _arabic_to_chinese_simple(str(remainder))
            elif remainder >= 100:
                result += _arabic_to_chinese_simple(str(remainder))
            return result
        elif num < 100000000:
            wan = num // 10000
            remainder = num % 10000
            result = _arabic_to_chinese_simple(str(wan)) + '万'
            if remainder > 0 and remainder < 1000:
                result += '零' + _arabic_to_chinese_simple(str(remainder))
            elif remainder >= 1000:
                result += _arabic_to_chinese_simple(str(remainder))
            return result
        else:
            yi = num // 100000000
            remainder = num % 100000000
            result = _arabic_to_chinese_simple(str(yi)) + '亿'
            if remainder > 0:
                result += _arabic_to_chinese_simple(str(remainder))
            return result
    except:
        return num_str

def _normalize_number_reading(text):
    """规范化数字读音，将阿拉伯数字和中文数字转换为统一的拼音比较格式

    处理规则：
    1. 年份：2023年 → 二零二三年（逐位读）
    2. 普通数字：15 → 十五（完整读）
    3. 百分比：15% → 百分之十五
    4. 范围：5-10 → 五到十，12%-20% → 百分之十二到百分之二十

    例如：
    - "2023年" → "二零二三年"
    - "15亿至25亿美元" → "十五亿至二十五亿美元"
    - "12%-20%" → "百分之十二到百分之二十"
    - "5-10年" → "五到十年"
    """
    result = text

    # 1. 先处理年份（必须先处理，因为年份是4位数字特殊读法）
    # 例如：2023年 → 二零二三年
    def convert_year(match):
        year = match.group(1)
        return ''.join(CN_NUMBERS_READING.get(d, d) for d in year) + '年'
    result = re.sub(r'(\d{4})年', convert_year, result)

    # 2. 处理百分比范围：12%-20% → 百分之十二到百分之二十（必须在单独百分比之前处理）
    def convert_percent_range(match):
        num1 = match.group(1)
        num2 = match.group(2)
        return '百分之' + _arabic_to_chinese_simple(num1) + '到百分之' + _arabic_to_chinese_simple(num2)
    result = re.sub(r'(\d+)%-(\d+)%', convert_percent_range, result)

    # 3. 处理范围表达式：5-10 → 五到十，5-10年 → 五到十年
    def convert_range(match):
        num1 = match.group(1)
        num2 = match.group(2)
        suffix = match.group(3) if match.group(3) else ''
        return _arabic_to_chinese_simple(num1) + '到' + _arabic_to_chinese_simple(num2) + suffix
    result = re.sub(r'(\d+)-(\d+)(年|月|日|元|美元|亿|万|)?', convert_range, result)

    # 4. 处理百分比：15% → 百分之十五
    def convert_percent(match):
        num = match.group(1)
        return '百分之' + _arabic_to_chinese_simple(num)
    result = re.sub(r'(\d+)%', convert_percent, result)

    # 5. 处理带单位的数字：15亿、25美元
    def convert_with_unit(match):
        num = match.group(1)
        unit = match.group(2)
        return _arabic_to_chinese_simple(num) + unit
    result = re.sub(r'(\d+)([亿万千百元块美])', convert_with_unit, result)

    # 6. 处理剩余的纯阿拉伯数字：60 → 六十
    def convert_number(match):
        num = match.group(1)
        return _arabic_to_chinese_simple(num)
    result = re.sub(r'\b(\d+)\b', convert_number, result)

    # 7. 清理多余的空格
    result = re.sub(r'\s+', '', result)

    return result

def _same_pinyin(a: str, b: str) -> bool:
    """Return True if two strings have identical pinyin with tones.

    智能同音字识别：
    - 长度相同时：逐字比较拼音（如 他/她）
    - 长度不同时：检查是否都是同音词（如 的/地得/的）
    - 先进行数字读音规范化，然后再比较拼音

    性能优化：使用LRU缓存避免重复计算拼音
    """
    if not a or not b:
        return False

    # 先规范化数字读音
    a_normalized = _normalize_number_reading(a)
    b_normalized = _normalize_number_reading(b)

    # Remove punctuation before comparing
    a_clean = _normalize(a_normalized)
    b_clean = _normalize(b_normalized)

    if not a_clean or not b_clean:
        return False

    # 获取拼音列表
    pa = [_get_char_pinyin(c) for c in a_clean]
    pb = [_get_char_pinyin(c) for c in b_clean]

    # 长度相同时：直接比较
    if len(pa) == len(pb):
        return pa == pb

    # 长度不同时：检查是否是同音词
    # 例如："的" vs "地得" 都是 "de"
    # 如果A是B的子集且拼音相同，或者B是A的子集且拼音相同
    if len(pa) < len(pb):
        # 检查是否所有A的拼音都能在B中找到对应
        return _is_subsequence_pinyin(pa, pb)
    else:
        # 检查是否所有B的拼音都能在A中找到对应
        return _is_subsequence_pinyin(pb, pa)

def _is_subsequence_pinyin(shorter, longer):
    """检查较短的拼音序列是否是较长的拼音序列的同音子序列

    例如：["de"] 是否是 ["de", "de"] 的子序列（的 vs 地得）

    拼音格式：["声母", "韵母", "声调"] 如 ["d", "e", "5"]
    需要转换为字符串比较
    """
    if not shorter:
        return True
    if not longer:
        return False

    # 将拼音列表转换为字符串（如 ['d', 'e', '5'] -> "de5"）
    shorter_strs = [''.join(p) if isinstance(p, list) else str(p) for p in shorter]
    longer_strs = [''.join(p) if isinstance(p, list) else str(p) for p in longer]

    # 如果长短语的拼音集合相同（考虑重复），认为是同音
    # 例如："的"(de) 和 "地得"(de, de) 都包含 "de"
    from collections import Counter
    shorter_counter = Counter(shorter_strs)
    longer_counter = Counter(longer_strs)

    # 检查较短序列的每个拼音是否都在较长序列中
    for pinyin, count in shorter_counter.items():
        if longer_counter.get(pinyin, 0) < count:
            return False

    return True

def _is_punct(ch):
    return bool(re.match(r'[，。！？；：、\u201c\u201d\u2018\u2019（）【】《》…—·\s,.!?;:\'"()\[\]{}\-]', ch))

def _normalize(text):
    """Remove punctuation for comparison."""
    return re.sub(r'[，。！？；：、\u201c\u201d\u2018\u2019（）【】《》…—·\s,.!?;:\'"()\[\]{}\-]', '', text)

def _punct_only_diff(a, b):
    """Return True if a and b differ only in punctuation (same chars after removing punct)."""
    na, nb = _normalize(a), _normalize(b)
    if na != nb:
        return False
    # Same content, check if sentence breaks match
    return _sentence_breaks_match(a, b)

def _get_sentence_breaks(text):
    """Extract sentence break positions (char offsets after removing punct) from sentence-ending punctuation."""
    breaks = []
    char_idx = 0
    for ch in text:
        if _is_punct(ch):
            if ch in '。！？.!?\n':
                breaks.append(char_idx)
        else:
            char_idx += 1
    return breaks

def _sentence_breaks_match(doc_text, audio_text):
    """Check if audio sentence breaks align with doc sentence breaks."""
    doc_breaks = _get_sentence_breaks(doc_text)
    audio_breaks = _get_sentence_breaks(audio_text)
    if not doc_breaks and not audio_breaks:
        return True
    if not doc_breaks or not audio_breaks:
        return len(doc_breaks) == len(audio_breaks)
    return doc_breaks == audio_breaks

def _segment(text: str) -> List[str]:
    """Jieba word segmentation, filter empty tokens.

    性能优化：确保jieba只初始化一次
    """
    _ensure_jieba_initialized()
    return [w for w in jieba.cut(text) if w.strip()]

def _find_paragraph(doc_paragraphs, doc_text_norm, word_pos, doc_words):
    """Map a word position in doc_words back to paragraph index."""
    # Build char offset for each word
    char_offset = 0
    for i, w in enumerate(doc_words):
        if i == word_pos:
            break
        char_offset += len(w)
    # Find which paragraph this char offset falls in
    running = 0
    for idx, p in enumerate(doc_paragraphs):
        plen = len(_normalize(p))
        if running + plen > char_offset:
            return idx
        running += plen
    return len(doc_paragraphs) - 1

def compare_texts(audio_text, doc_text, config, word_timestamps=None):
    """Algorithm-based word-level diff using jieba + SequenceMatcher."""
    doc_paragraphs = [p.strip() for p in doc_text.split('\n') if p.strip()]
    confidence_threshold = config.get('confidence_threshold', 0.0)

    # Normalize and segment
    audio_norm = _normalize(audio_text)
    doc_norm = _normalize(doc_text)
    audio_words = _segment(audio_norm)
    doc_words = _segment(doc_norm)

    # Build char->timestamp mapping from word_timestamps
    ts_map = {}  # audio char offset -> {start, end, confidence}
    if word_timestamps:
        offset = 0
        for wt in word_timestamps:
            w = _normalize(wt['word'])
            for i in range(len(w)):
                ts_map[offset + i] = {'start': wt['start'], 'end': wt['end'], 'confidence': wt.get('confidence', 1.0)}
            offset += len(w)

    # Diff
    matcher = SequenceMatcher(None, doc_words, audio_words)
    raw_diffs = []

    # Track audio char offset per audio_words position
    audio_char_offsets = []
    off = 0
    for w in audio_words:
        audio_char_offsets.append(off)
        off += len(w)

    for tag, i1, i2, j1, j2 in matcher.get_opcodes():
        if tag == 'equal':
            continue

        doc_fragment = ''.join(doc_words[i1:i2])
        audio_fragment = ''.join(audio_words[j1:j2])

        # Skip filler words
        if tag == 'insert' and audio_fragment in FILLER_WORDS:
            continue
        if tag == 'delete' and doc_fragment in FILLER_WORDS:
            continue
        if tag == 'replace':
            if doc_fragment in FILLER_WORDS and audio_fragment in FILLER_WORDS:
                continue
            # Same pinyin+tone = same pronunciation, not a real diff
            if _same_pinyin(doc_fragment, audio_fragment):
                continue
            # Punctuation-only difference: if sentence breaks match, not a diff
            if _punct_only_diff(doc_fragment, audio_fragment):
                continue

        # Skip single punctuation or whitespace-only diffs
        if not doc_fragment.strip() and not audio_fragment.strip():
            continue
        # Skip pure punctuation fragments
        if all(_is_punct(c) or not c.strip() for c in doc_fragment) and all(_is_punct(c) or not c.strip() for c in audio_fragment):
            continue

        pos = _find_paragraph(doc_paragraphs, doc_norm, i1, doc_words)

        # Get timestamp and confidence for this diff
        ts_start = ts_end = None
        confidence = 1.0
        if ts_map and j1 < len(audio_char_offsets):
            char_off = audio_char_offsets[j1]
            if char_off in ts_map:
                ts_start = ts_map[char_off]['start']
                confidence = ts_map[char_off]['confidence']
            if j2 > 0 and j2 - 1 < len(audio_char_offsets):
                end_off = audio_char_offsets[j2 - 1]
                if end_off in ts_map:
                    ts_end = ts_map[end_off]['end']

        diff_entry = {
            'docText': doc_fragment,
            'audioText': audio_fragment,
            'type': 'mismatch' if tag == 'replace' else ('missing_in_audio' if tag == 'delete' else 'extra_in_audio'),
            'position': pos,
            'confidence': confidence,
            'uncertain': confidence < confidence_threshold if confidence_threshold > 0 else False,
        }
        if ts_start is not None:
            diff_entry['time_start'] = ts_start
        if ts_end is not None:
            diff_entry['time_end'] = ts_end

        raw_diffs.append(diff_entry)

    n_mismatch = sum(1 for d in raw_diffs if d['type'] == 'mismatch')
    n_missing = sum(1 for d in raw_diffs if d['type'] == 'missing_in_audio')
    n_extra = sum(1 for d in raw_diffs if d['type'] == 'extra_in_audio')

    # Check sentence break alignment
    break_ok = _sentence_breaks_match(doc_text, audio_text)
    break_note = '' if break_ok else '\n⚠ 语音断句位置与原文不一致'

    # WER/CER metrics
    doc_str = ' '.join(doc_words)
    audio_str = ' '.join(audio_words)
    wer_val = wer(doc_str, audio_str) if doc_str else 0
    cer_val = cer(doc_norm, audio_norm) if doc_norm else 0
    accuracy_word = max(0, (1 - wer_val) * 100)
    accuracy_char = max(0, (1 - cer_val) * 100)

    summary = (f'共{len(raw_diffs)}处差异：{n_mismatch}处误读，{n_missing}处漏读，{n_extra}处多读{break_note}\n'
               f'词准确率 {accuracy_word:.1f}% | 字准确率 {accuracy_char:.1f}%')

    return {
        'diffs': raw_diffs, 'summary': summary,
        'wer': wer_val, 'cer': cer_val,
        'accuracy_word': accuracy_word, 'accuracy_char': accuracy_char,
    }

# --- LLM calls kept for test_llm ---
def _call_claude(prompt, api_key, model):
    r = requests.post('https://api.anthropic.com/v1/messages', timeout=30,
        headers={'Content-Type': 'application/json', 'x-api-key': api_key, 'anthropic-version': '2023-06-01'},
        json={'model': model, 'max_tokens': 100, 'messages': [{'role': 'user', 'content': prompt}]})
    if r.status_code == 401:
        raise Exception('API Key 无效或已过期')
    elif r.status_code == 429:
        raise Exception('请求频率超限，请稍后再试')
    elif r.status_code >= 500:
        raise Exception(f'服务器错误 (HTTP {r.status_code})')
    r.raise_for_status()
    data = r.json()
    return data.get('content', [{}])[0].get('text', '')

def _call_openai_compat(prompt, api_key, endpoint, model):
    r = requests.post(endpoint, timeout=30,
        headers={'Content-Type': 'application/json', 'Authorization': f'Bearer {api_key}'},
        json={'model': model, 'messages': [{'role': 'user', 'content': prompt}], 'temperature': 0.1, 'max_tokens': 100})
    if r.status_code == 401:
        raise Exception('API Key 无效或已过期')
    elif r.status_code == 429:
        raise Exception('请求频率超限，请稍后再试')
    elif r.status_code >= 500:
        raise Exception(f'服务器错误 (HTTP {r.status_code})')
    r.raise_for_status()
    data = r.json()
    return data.get('choices', [{}])[0].get('message', {}).get('content', '')

def test_llm(provider_id, api_key, model=None):
    from config import LLM_PROVIDERS
    provider = LLM_PROVIDERS[provider_id]
    m = model or provider['default_model']

    # Basic validation
    if not api_key or not api_key.strip():
        return False, '请先输入 API Key'

    # Provider-specific format validation
    if provider_id == 'openai' and not api_key.startswith('sk-'):
        return False, 'OpenAI API Key 格式错误（应以 sk- 开头）'
    if provider_id == 'claude' and (len(api_key) < 20 or not api_key.startswith('sk-ant-')):
        return False, 'Claude API Key 格式错误（应以 sk-ant- 开头）'

    prompt = '请只回复"成功"两个字，不要添加其他内容。'
    try:
        content = ''
        if provider_id == 'claude':
            content = _call_claude(prompt, api_key, m)
        else:
            content = _call_openai_compat(prompt, api_key, provider['endpoint'], m)

        if content and ('成功' in content or 'OK' in content.upper() or '连接成功' in content):
            return True, '✓ 连接成功，API 可用'
        elif content:
            return True, f'✓ 连接成功（响应: {content[:30].strip()}）'
        else:
            return False, '连接成功但无响应内容'
    except requests.exceptions.Timeout:
        return False, '连接超时，请检查网络或稍后再试'
    except requests.exceptions.ConnectionError:
        return False, '网络连接失败，请检查网络设置'
    except Exception as e:
        error_msg = str(e)
        if 'API Key' in error_msg or '401' in error_msg:
            return False, 'API Key 无效，请检查后重试'
        elif '频率' in error_msg or '429' in error_msg:
            return False, '请求过于频繁，请稍后再试'
        else:
            return False, f'连接失败: {error_msg[:80]}'

import os, sys, tempfile, subprocess, requests, hmac, hashlib, base64, json, time, atexit
from urllib.parse import quote
from datetime import datetime, timezone
from typing import List, Callable, Optional, Dict, Any
import opencc

_funasr_proc = None
_converter = None

# ===== 临时文件管理 =====
_temp_files: set = set()

def _make_temp_file(suffix: str = '') -> str:
    """创建临时文件并注册清理"""
    fd, path = tempfile.mkstemp(suffix=suffix)
    os.close(fd)
    _temp_files.add(path)
    return path

def _cleanup_temp_files():
    """清理所有临时文件"""
    for filepath in list(_temp_files):
        try:
            if os.path.exists(filepath):
                os.remove(filepath)
        except Exception:
            pass
    _temp_files.clear()

# 注册退出时清理
atexit.register(_cleanup_temp_files)

# 隐藏子进程窗口的标志 (Windows: 0x08000000, 其他: 0)
_HIDE_WINDOW = 0x08000000 if sys.platform == 'win32' else 0
# 同时设置 subprocess.CREATE_NO_WINDOW (如果可用)
if hasattr(subprocess, 'CREATE_NO_WINDOW'):
    _HIDE_WINDOW = getattr(subprocess, 'CREATE_NO_WINDOW', _HIDE_WINDOW)

def _get_converter():
    """Get OpenCC converter instance for Traditional to Simplified Chinese."""
    global _converter
    if _converter is None:
        try:
            import opencc
            _converter = opencc.OpenCC('t2s')  # Traditional to Simplified
        except ImportError:
            _converter = None
    return _converter

def _to_simplified(text):
    """Convert Traditional Chinese to Simplified Chinese.
    English text will be preserved as-is.
    """
    import re

    # 统计中文字符（不包括标点符号）
    chinese_chars = len(re.findall(r'[\u4e00-\u9fff]', text))

    # 统计总字符数（不包括空格）
    total_chars = len(re.sub(r'\s+', '', text))

    # 如果没有中文字符或中文占比少于15%，认为是英文，不转换
    if total_chars == 0 or chinese_chars == 0 or chinese_chars / total_chars < 0.15:
        # 英文为主或无中文，不转换
        return text

    # 包含足够比例的中文，进行繁简转换
    converter = _get_converter()
    if converter:
        try:
            return converter.convert(text)
        except:
            pass
    return text  # Return original if conversion fails

def preprocess_audio(filepath: str, progress_cb: Optional[Callable] = None, skip_if_compatible: bool = True) -> str:
    """Normalize volume and reduce noise using ffmpeg. Returns path to processed file.

    性能优化：
    - 如果音频已是16kHz单声道，可跳过预处理
    - 使用更快的ffmpeg参数
    """
    # 如果允许跳过且音频已符合格式要求，直接返回
    if skip_if_compatible:
        try:
            # 快速检查音频格式
            probe_result = subprocess.run(
                ['ffprobe', '-v', 'quiet', '-print_format', 'json', '-show_streams', filepath],
                capture_output=True, text=True, creationflags=_HIDE_WINDOW, timeout=5
            )
            streams = json.loads(probe_result.stdout).get('streams', [])
            for stream in streams:
                if stream.get('codec_type') == 'audio':
                    sample_rate = int(stream.get('sample_rate', 0))
                    channels = int(stream.get('channels', 0))
                    # 如果已经是16kHz单声道，跳过预处理
                    if sample_rate == 16000 and channels == 1:
                        if progress_cb:
                            progress_cb('音频格式检查完成，跳过预处理')
                        return filepath
        except:
            pass  # 检查失败，继续预处理

    if progress_cb:
        progress_cb('正在预处理音频（快速模式）...')

    out = _make_temp_file('_vdc_preprocessed.wav')

    # 简化的音频处理：只转格式，不做复杂处理（更快）
    subprocess.run([
        'ffmpeg', '-y', '-i', filepath,
        '-ac', '1', '-ar', '16000',  # 只设置单声道和采样率
        '-acodec', 'pcm_s16le',      # 使用PCM编码（更快）
        out
    ], capture_output=True, creationflags=_HIDE_WINDOW)

    return out if os.path.exists(out) else filepath

def _ensure_funasr_running(progress_cb: Optional[Callable] = None):
    """Auto-start FunASR server if not running.

    性能优化：
    - 更快的健康检查间隔
    - 并行启动和检查
    - 模型预热
    """
    global _funasr_proc
    try:
        # 快速健康检查（1秒超时）
        r = requests.get('http://localhost:8765/health', timeout=1)
        if r.status_code == 200:
            return
    except:
        pass

    if progress_cb:
        progress_cb('正在启动FunASR服务...')

    # Try to start the server
    python_exe = os.path.expanduser('~/funasr-venv/Scripts/python.exe')
    server_script = os.path.expanduser('~/.clawdbot/skills/funasr-transcribe/scripts/server.py')
    if not os.path.exists(python_exe) or not os.path.exists(server_script):
        raise Exception('FunASR环境未安装，请检查 ~/funasr-venv 和 ~/.clawdbot/skills/funasr-transcribe')

    _funasr_proc = subprocess.Popen(
        [python_exe, server_script],
        stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL,
        creationflags=_HIDE_WINDOW,
    )

    # 快速等待服务就绪（最多30秒）
    for i in range(30):
        time.sleep(0.5)  # 更短的检查间隔
        try:
            r = requests.get('http://localhost:8765/health', timeout=1)
            if r.status_code == 200:
                if progress_cb and i > 5:
                    progress_cb('FunASR服务已就绪')
                return
        except:
            pass

    raise Exception('FunASR服务启动超时，请手动运行:\n' + python_exe + ' ' + server_script)

def transcribe_audio(filepath, config, progress_cb=None):
    from config import get_builtin_keys
    pid = config['asr_provider']
    keys = config.get('asr_keys', {}).get(pid, {})
    # Use builtin keys if available
    if not keys:
        keys = get_builtin_keys(pid)
    # Preprocess audio
    if config.get('preprocess', True):
        filepath = preprocess_audio(filepath, progress_cb)
    if pid == 'funasr':
        text = _transcribe_funasr(filepath, progress_cb)
    elif pid == 'aliyun':
        text = _transcribe_chunked(filepath, lambda f: _transcribe_aliyun(f, keys), progress_cb)
    elif pid == 'baidu' or pid == 'baidu_builtin':
        text = _transcribe_baidu_chunked(filepath, keys, progress_cb)
    elif pid == 'groq_whisper':
        text = _transcribe_ffmpeg_chunked(filepath, lambda f: _transcribe_groq(f, keys['key']), progress_cb)
    elif pid == 'openai_whisper':
        text = _transcribe_ffmpeg_chunked(filepath, lambda f: _transcribe_whisper(f, keys['key']), progress_cb)
    else:
        raise Exception(f'{pid} 转写暂未实现')

    # ===== 强制转换为简体中文 =====
    # 所有转写引擎的结果都必须转换为简体中文后再与原文比对
    text = _to_simplified(text)
    return text

def transcribe_with_timestamps(filepath, config, progress_cb=None):
    """Transcribe with word-level timestamps using stable-ts."""
    if config.get('preprocess', True):
        filepath = preprocess_audio(filepath, progress_cb)
    if progress_cb: progress_cb('正在加载stable-ts模型（首次较慢）...')
    import stable_whisper
    model = stable_whisper.load_model('base')
    if progress_cb: progress_cb('正在转写并对齐时间戳...')
    result = model.transcribe(filepath, language='zh')
    words = []
    for seg in result.segments:
        for w in seg.words:
            words.append({'word': w.word.strip(), 'start': w.start, 'end': w.end, 'confidence': getattr(w, 'probability', 0.0)})
    text = ''.join(w['word'] for w in words)

    # ===== 强制转换为简体中文 =====
    # 转换文本和时间戳中的词语
    text = _to_simplified(text)
    for w in words:
        w['word'] = _to_simplified(w['word'])

    return text, words

# --- FunASR (local server) ---
def _transcribe_funasr(filepath, progress_cb=None):
    if progress_cb: progress_cb('正在启动FunASR服务...')
    _ensure_funasr_running()
    if progress_cb: progress_cb('正在调用本地FunASR服务...')
    r = requests.post('http://localhost:8765/transcribe',
        json={'file_path': os.path.abspath(filepath)}, timeout=600)
    data = r.json()
    if data.get('success'):
        text = data.get('text', '')
        # Convert Traditional Chinese to Simplified Chinese
        text = _to_simplified(text)
        return text
    raise Exception(data.get('error', '转写失败'))

# --- Chunked transcription for cloud APIs ---
def _transcribe_chunked(filepath, transcribe_fn, progress_cb=None):
    from pydub import AudioSegment
    if progress_cb: progress_cb('正在加载音频...')
    audio = AudioSegment.from_file(filepath)
    duration_s = len(audio) / 1000

    if duration_s <= 60:
        if progress_cb: progress_cb('正在转写...')
        return transcribe_fn(filepath)

    # Split into chunks at silence points
    from pydub.silence import split_on_silence
    if progress_cb: progress_cb('长语音，正在分块...')
    chunks = split_on_silence(audio, min_silence_len=500, silence_thresh=-40, keep_silence=300)

    # Merge small chunks, split large ones to keep each ≤ 55s
    merged = []
    buf = AudioSegment.empty()
    for c in chunks:
        if len(buf) + len(c) <= 55000:
            buf += c
        else:
            if len(buf) > 0:
                merged.append(buf)
            if len(c) > 55000:
                # Hard split
                for i in range(0, len(c), 55000):
                    merged.append(c[i:i+55000])
            else:
                buf = c
                continue
            buf = AudioSegment.empty()
    if len(buf) > 0:
        merged.append(buf)

    if not merged:
        merged = [audio]

    results = []
    tmpdir = tempfile.mkdtemp()
    for i, chunk in enumerate(merged):
        if progress_cb: progress_cb(f'转写分块 {i+1}/{len(merged)}...')
        tmp = os.path.join(tmpdir, f'chunk_{i}.wav')
        chunk.export(tmp, format='wav')
        results.append(transcribe_fn(tmp))
        os.remove(tmp)

    return ' '.join(results)

# --- FFmpeg-based chunked transcription (no pydub dependency) ---
def _transcribe_ffmpeg_chunked(filepath, transcribe_fn, progress_cb=None):
    if progress_cb: progress_cb('正在检测音频时长...')
    # Get duration via ffprobe
    result = subprocess.run(['ffprobe', '-v', 'quiet', '-print_format', 'json', '-show_format', filepath],
        capture_output=True, text=True, creationflags=getattr(subprocess, 'CREATE_NO_WINDOW', 0))
    duration_s = float(json.loads(result.stdout).get('format', {}).get('duration', 0))

    if duration_s <= 55:
        if progress_cb: progress_cb('正在转写...')
        return transcribe_fn(filepath)

    # Split into 55-second chunks using ffmpeg
    tmpdir = tempfile.mkdtemp()
    chunk_pattern = os.path.join(tmpdir, 'chunk_%03d.wav')
    subprocess.run(['ffmpeg', '-i', filepath, '-f', 'segment', '-segment_time', '55',
        '-ac', '1', '-ar', '16000', '-y', chunk_pattern],
        capture_output=True, creationflags=getattr(subprocess, 'CREATE_NO_WINDOW', 0))

    chunks = sorted([os.path.join(tmpdir, f) for f in os.listdir(tmpdir) if f.startswith('chunk_')])
    if not chunks:
        if progress_cb: progress_cb('正在转写...')
        return transcribe_fn(filepath)

    results = []
    for i, chunk in enumerate(chunks):
        if progress_cb: progress_cb(f'转写分块 {i+1}/{len(chunks)}...')
        results.append(transcribe_fn(chunk))
        os.remove(chunk)
    os.rmdir(tmpdir)
    return ' '.join(results)

# --- Aliyun ASR ---
def _transcribe_aliyun(filepath, keys):
    ak_id, ak_secret, app_key = keys.get('key',''), keys.get('secret',''), keys.get('appKey','')
    if not all([ak_id, ak_secret, app_key]):
        raise Exception('请配置阿里云 AccessKey ID、Secret 和 AppKey')

    # Get token
    nonce = os.urandom(8).hex()
    ts = datetime.now(timezone.utc).strftime('%Y-%m-%dT%H:%M:%SZ')
    params = {
        'AccessKeyId': ak_id, 'Action': 'CreateToken', 'Format': 'JSON',
        'RegionId': 'cn-shanghai', 'SignatureMethod': 'HMAC-SHA1',
        'SignatureNonce': nonce, 'SignatureVersion': '1.0',
        'Timestamp': ts, 'Version': '2019-02-28',
    }
    canon = '&'.join(f'{quote(k, safe="")}={quote(params[k], safe="")}' for k in sorted(params))
    sts = f'GET&{quote("/", safe="")}&{quote(canon, safe="")}'
    sig = base64.b64encode(hmac.new((ak_secret + '&').encode(), sts.encode(), hashlib.sha1).digest()).decode()
    params['Signature'] = sig
    query = '&'.join(f'{quote(k, safe="")}={quote(v, safe="")}' for k, v in params.items())
    resp = requests.get(f'https://nls-meta.cn-shanghai.aliyuncs.com/?{query}', timeout=10)
    token = resp.json().get('Token', {}).get('Id')
    if not token:
        raise Exception('获取阿里云Token失败: ' + resp.text[:200])

    # Transcribe
    with open(filepath, 'rb') as f:
        audio_data = f.read()
    url = f'https://nls-gateway-cn-shanghai.aliyuncs.com/stream/v1/asr?appkey={app_key}&format=wav&sample_rate=16000&enable_punctuation_prediction=true&enable_inverse_text_normalization=true'
    resp = requests.post(url, headers={'X-NLS-Token': token, 'Content-Type': 'application/octet-stream'}, data=audio_data, timeout=60)
    result = resp.json()
    if result.get('status') == 20000000 and result.get('result'):
        return result['result']
    raise Exception('阿里云识别失败: ' + json.dumps(result, ensure_ascii=False)[:200])

# --- Baidu ASR chunked (with proper format conversion) ---
def _transcribe_baidu_chunked(filepath, keys, progress_cb=None):
    """Handle Baidu ASR with automatic chunking for long audio."""
    # First, convert to proper format (16kHz, mono)
    tmp_normalized = os.path.join(tempfile.gettempdir(), 'baidu_normalized.wav')
    if progress_cb:
        progress_cb('正在转换音频格式...')
    subprocess.run([
        'ffmpeg', '-y', '-i', filepath,
        '-acodec', 'pcm_s16le',
        '-ac', '1',
        '-ar', '16000',
        tmp_normalized
    ], capture_output=True, creationflags=getattr(subprocess, 'CREATE_NO_WINDOW', 0))

    if not os.path.exists(tmp_normalized):
        # Fallback: use original
        tmp_normalized = filepath

    # Get duration
    result = subprocess.run(['ffprobe', '-v', 'quiet', '-print_format', 'json', '-show_format', tmp_normalized],
        capture_output=True, text=True, creationflags=getattr(subprocess, 'CREATE_NO_WINDOW', 0))
    try:
        duration_s = float(json.loads(result.stdout).get('format', {}).get('duration', 0))
    except:
        duration_s = 0

    # If short enough, transcribe directly
    if duration_s <= 55:
        if progress_cb:
            progress_cb('正在转写...')
        text = _transcribe_baidu_single(tmp_normalized, keys)
        if tmp_normalized != filepath and os.path.exists(tmp_normalized):
            os.remove(tmp_normalized)
        return text

    # Long audio: split into 55-second chunks
    if progress_cb:
        progress_cb(f'长语音({int(duration_s)}秒)，正在分段...')
    tmpdir = tempfile.mkdtemp()
    chunk_pattern = os.path.join(tmpdir, 'chunk_%03d.wav')
    subprocess.run(['ffmpeg', '-i', tmp_normalized, '-f', 'segment', '-segment_time', '55',
        '-ac', '1', '-ar', '16000', '-y', chunk_pattern],
        capture_output=True, creationflags=getattr(subprocess, 'CREATE_NO_WINDOW', 0))

    chunks = sorted([os.path.join(tmpdir, f) for f in os.listdir(tmpdir) if f.startswith('chunk_')])

    if not chunks:
        if tmp_normalized != filepath and os.path.exists(tmp_normalized):
            os.remove(tmp_normalized)
        raise Exception('音频分段失败')

    results = []
    for i, chunk in enumerate(chunks):
        if progress_cb:
            progress_cb(f'转写分块 {i+1}/{len(chunks)}...')
        try:
            text = _transcribe_baidu_single(chunk, keys)
            results.append(text)
        except Exception as e:
            # Continue with next chunk on error
            results.append(f'[{e}]')
        os.remove(chunk)

    os.rmdir(tmpdir)
    if tmp_normalized != filepath and os.path.exists(tmp_normalized):
        os.remove(tmp_normalized)

    return ' '.join(results)

def _transcribe_baidu_single(filepath, keys):
    """Transcribe a single audio file (must be <= 60s)."""
    api_key, secret_key = keys.get('key', ''), keys.get('secret', '')
    app_id = keys.get('app_id', '')
    if not api_key or not secret_key:
        raise Exception('请配置百度 API Key 和 Secret Key')

    # Get access token with caching
    if not hasattr(_transcribe_baidu_single, '_token'):
        _transcribe_baidu_single._token = None
        _transcribe_baidu_single._token_keys = None

    if _transcribe_baidu_single._token_keys != (api_key, secret_key):
        resp = requests.post('https://aip.baidubce.com/oauth/2.0/token',
            params={'grant_type': 'client_credentials', 'client_id': api_key, 'client_secret': secret_key}, timeout=10)
        data = resp.json()
        token = data.get('access_token')
        if not token:
            raise Exception('获取百度Token失败: ' + resp.text[:200])
        _transcribe_baidu_single._token = token
        _transcribe_baidu_single._token_keys = (api_key, secret_key)
    else:
        token = _transcribe_baidu_single._token

    with open(filepath, 'rb') as f:
        audio_data = f.read()

    # Check audio length
    audio_len = len(audio_data)
    if audio_len > 2 * 1024 * 1024:
        raise Exception(f'音频文件过大({audio_len/1024/1024:.1f}MB)，请使用60秒以内的音频')

    # dev_pid: 1537=普通话(支持简单的英文识别), 1737=英语
    payload = {
        'format': 'wav',
        'rate': 16000,
        'channel': 1,
        'cuid': app_id or 'voice_doc_compare',
        'token': token,
        'speech': base64.b64encode(audio_data).decode(),
        'len': audio_len,
        'dev_pid': 1537  # 普通话
    }
    resp = requests.post('https://vop.baidu.com/server_api',
        json=payload, timeout=60)
    result = resp.json()
    err_no = result.get('err_no', -1)
    if err_no == 0:
        return ''.join(result.get('result', []))

    # 详细的错误码说明
    error_messages = {
        3301: '音频质量过差，无法识别',
        3302: '鉴权失败，请检查API Key',
        3303: '语音服务器后端问题',
        3307: '音频时长过长，超过60秒限制',
        3308: '音频过长',
        3309: '音频格式问题',
        3310: '音频采样率不正确',
        3311: '音频编码不正确',
        3312: '音频参数不正确',
        3333: '服务器错误',
        3001: '语音识别服务器内部错误',
        3003: '语音识别后端系统错误',
    }
    err_msg = error_messages.get(err_no, result.get('err_msg', '未知错误'))
    raise Exception(f'百度识别失败[{err_no}]: {err_msg}')

