import os, time, html

def _fmt(seconds):
    if seconds is None: return ''
    m, s = divmod(int(seconds), 60)
    ms = int((seconds - int(seconds)) * 100)
    return f'{m}:{s:02d}.{ms:02d}'

def generate_html_report(diffs, summary, audio_text, doc_text, audio_path=None, output_dir=None):
    if output_dir is None:
        output_dir = os.path.join(os.path.expanduser('~'), 'Desktop')

    doc_paragraphs = [p.strip() for p in doc_text.split('\n') if p.strip()]

    # Build annotated paragraphs
    diff_by_pos = {}
    for d in diffs:
        diff_by_pos.setdefault(d.get('position', 0), []).append(d)

    annotated = []
    for idx, para in enumerate(doc_paragraphs):
        if idx not in diff_by_pos:
            annotated.append(html.escape(para))
            continue

        para_diffs = diff_by_pos[idx]
        located = []
        used = set()
        for d in para_diffs:
            dt = d.get('docText', '')
            if d.get('type') == 'extra_in_audio' or not dt:
                located.append((len(para), len(para), d))
                continue
            start = 0
            while True:
                pos = para.find(dt, start)
                if pos == -1:
                    located.append((len(para), len(para), d))
                    break
                if pos not in used:
                    used.add(pos)
                    located.append((pos, pos + len(dt), d))
                    break
                start = pos + 1
        located.sort(key=lambda x: x[0])

        parts = []
        cursor = 0
        for start, end, d in located:
            dtype = d.get('type', 'mismatch')
            at = html.escape(d.get('audioText', ''))
            ts = _fmt(d.get('time_start'))
            uncertain = ' uncertain' if d.get('uncertain') else ''
            ts_attr = f' data-time="{d["time_start"]}"' if d.get('time_start') is not None else ''
            ts_label = f' <span class="ts">@{ts}</span>' if ts else ''

            if start > cursor:
                parts.append(html.escape(para[cursor:start]))

            if dtype == 'mismatch':
                parts.append(f'<span class="diff mismatch{uncertain}"{ts_attr}>{html.escape(para[start:end])}'
                             f'<span class="note">[误读为:"{at}"{ts_label}]</span></span>')
            elif dtype == 'missing_in_audio':
                parts.append(f'<span class="diff missing{uncertain}"{ts_attr}>{html.escape(para[start:end])}'
                             f'<span class="note">[漏读{ts_label}]</span></span>')
            elif dtype == 'extra_in_audio':
                parts.append(f'<span class="diff extra{uncertain}"{ts_attr}>'
                             f'<span class="note">[多读:"{at}"{ts_label}]</span></span>')
            cursor = end

        if cursor < len(para):
            parts.append(html.escape(para[cursor:]))
        annotated.append(''.join(parts))

    audio_tag = ''
    if audio_path and os.path.exists(audio_path):
        audio_tag = f'<audio id="player" controls src="file:///{audio_path.replace(os.sep, "/")}"></audio>'

    body = '\n'.join(f'<p>{a}</p>' for a in annotated)
    summary_html = html.escape(summary).replace('\n', '<br>')

    content = f'''<!DOCTYPE html>
