    'baichuan': {'name': '百川智能', 'region': 'cn', 'endpoint': 'https://api.baichuan-ai.com/v1/chat/completions', 'default_model': 'Baichuan4'},
    'minimax': {'name': 'MiniMax', 'region': 'cn', 'endpoint': 'https://api.minimax.chat/v1/text/chatcompletion_v2', 'default_model': 'abab6.5s-chat'},
