    'groq': {'name': 'Groq', 'region': 'intl', 'endpoint': 'https://api.groq.com/openai/v1/chat/completions', 'default_model': 'llama-3.1-70b-versatile'},
    'mistral': {'name': 'Mistral', 'region': 'intl', 'endpoint': 'https://api.mistral.ai/v1/chat/completions', 'default_model': 'mistral-large-latest'},
    'cohere': {'name': 'Cohere', 'region': 'intl', 'endpoint': 'https://api.cohere.com/v2/chat', 'default_model': 'command-r-plus'},
    'perplexity': {'name': 'Perplexity', 'region': 'intl', 'endpoint': 'https://api.perplexity.ai/chat/completions', 'default_model': 'sonar-pro'},
    'together': {'name': 'Together AI', 'region': 'intl', 'endpoint': 'https://api.together.xyz/v1/chat/completions', 'default_model': 'meta-llama/Llama-3-70b-chat-hf'},
