import os, sys, tempfile, subprocess, requests, hmac, hashlib, base64, json, time, atexit
from urllib.parse import quote
from datetime import datetime, timezone
from typing import List, Callable, Optional, Dict, Any
import opencc

_funasr_proc = None
_converter = None

# ===== 临时文件管理 =====
_temp_files: set = set()

def _make_temp_file(suffix: str = '') -> str:
    """创建临时文件并注册清理"""
    fd, path = tempfile.mkstemp(suffix=suffix)
    os.close(fd)
    _temp_files.add(path)
    return path

def _cleanup_temp_files():
    """清理所有临时文件"""
    for filepath in list(_temp_files):
        try:
            if os.path.exists(filepath):
                os.remove(filepath)
        except Exception:
            pass
    _temp_files.clear()

# 注册退出时清理
atexit.register(_cleanup_temp_files)

# 隐藏子进程窗口的标志 (Windows: 0x08000000, 其他: 0)
_HIDE_WINDOW = 0x08000000 if sys.platform == 'win32' else 0
# 同时设置 subprocess.CREATE_NO_WINDOW (如果可用)
if hasattr(subprocess, 'CREATE_NO_WINDOW'):
    _HIDE_WINDOW = getattr(subprocess, 'CREATE_NO_WINDOW', _HIDE_WINDOW)

def _get_converter():
    """Get OpenCC converter instance for Traditional to Simplified Chinese."""
    global _converter
    if _converter is None:
        try:
            import opencc
            _converter = opencc.OpenCC('t2s')  # Traditional to Simplified
        except ImportError:
            _converter = None
    return _converter

def _to_simplified(text):
    """Convert Traditional Chinese to Simplified Chinese.
    English text will be preserved as-is.
    """
    import re

    # 统计中文字符（不包括标点符号）
    chinese_chars = len(re.findall(r'[\u4e00-\u9fff]', text))

    # 统计总字符数（不包括空格）
    total_chars = len(re.sub(r'\s+', '', text))

    # 如果没有中文字符或中文占比少于15%，认为是英文，不转换
    if total_chars == 0 or chinese_chars == 0 or chinese_chars / total_chars < 0.15:
        # 英文为主或无中文，不转换
        return text

    # 包含足够比例的中文，进行繁简转换
    converter = _get_converter()
    if converter:
        try:
            return converter.convert(text)
        except:
            pass
    return text  # Return original if conversion fails

def preprocess_audio(filepath: str, progress_cb: Optional[Callable] = None, skip_if_compatible: bool = True) -> str:
    """Normalize volume and reduce noise using ffmpeg. Returns path to processed file.

    性能优化：
    - 如果音频已是16kHz单声道，可跳过预处理
    - 使用更快的ffmpeg参数
    """
    # 如果允许跳过且音频已符合格式要求，直接返回
    if skip_if_compatible:
        try:
            # 快速检查音频格式
            probe_result = subprocess.run(
                ['ffprobe', '-v', 'quiet', '-print_format', 'json', '-show_streams', filepath],
                capture_output=True, text=True, creationflags=_HIDE_WINDOW, timeout=5
            )
            streams = json.loads(probe_result.stdout).get('streams', [])
            for stream in streams:
                if stream.get('codec_type') == 'audio':
                    sample_rate = int(stream.get('sample_rate', 0))
                    channels = int(stream.get('channels', 0))
                    # 如果已经是16kHz单声道，跳过预处理
                    if sample_rate == 16000 and channels == 1:
                        if progress_cb:
                            progress_cb('音频格式检查完成，跳过预处理')
                        return filepath
        except:
            pass  # 检查失败，继续预处理

    if progress_cb:
        progress_cb('正在预处理音频（快速模式）...')

    out = _make_temp_file('_vdc_preprocessed.wav')

    # 简化的音频处理：只转格式，不做复杂处理（更快）
    subprocess.run([
        'ffmpeg', '-y', '-i', filepath,
        '-ac', '1', '-ar', '16000',  # 只设置单声道和采样率
        '-acodec', 'pcm_s16le',      # 使用PCM编码（更快）
        out
    ], capture_output=True, creationflags=_HIDE_WINDOW)

    return out if os.path.exists(out) else filepath

def _ensure_funasr_running(progress_cb: Optional[Callable] = None):
    """Auto-start FunASR server if not running.

    性能优化：
    - 更快的健康检查间隔
    - 并行启动和检查
    - 模型预热
    """
    global _funasr_proc
    try:
        # 快速健康检查（1秒超时）
        r = requests.get('http://localhost:8765/health', timeout=1)
        if r.status_code == 200:
            return
    except:
        pass

    if progress_cb:
        progress_cb('正在启动FunASR服务...')

    # Try to start the server
    python_exe = os.path.expanduser('~/funasr-venv/Scripts/python.exe')
    server_script = os.path.expanduser('~/.clawdbot/skills/funasr-transcribe/scripts/server.py')
    if not os.path.exists(python_exe) or not os.path.exists(server_script):
        raise Exception('FunASR环境未安装，请检查 ~/funasr-venv 和 ~/.clawdbot/skills/funasr-transcribe')

    _funasr_proc = subprocess.Popen(
        [python_exe, server_script],
        stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL,
        creationflags=_HIDE_WINDOW,
    )

    # 快速等待服务就绪（最多30秒）
    for i in range(30):
        time.sleep(0.5)  # 更短的检查间隔
        try:
            r = requests.get('http://localhost:8765/health', timeout=1)
            if r.status_code == 200:
                if progress_cb and i > 5:
                    progress_cb('FunASR服务已就绪')
                return
        except:
            pass

    raise Exception('FunASR服务启动超时，请手动运行:\n' + python_exe + ' ' + server_script)

def transcribe_audio(filepath, config, progress_cb=None, return_timestamps=False):
    from config import get_builtin_keys
    pid = config['asr_provider']
    keys = config.get('asr_keys', {}).get(pid, {})
    # Use builtin keys if available
    if not keys:
        keys = get_builtin_keys(pid)
    # Preprocess audio
    if config.get('preprocess', True):
        filepath = preprocess_audio(filepath, progress_cb)
    if pid == 'funasr':
        text = _transcribe_funasr(filepath, progress_cb)
        return text if not return_timestamps else (text, None)
    elif pid == 'aliyun':
        text = _transcribe_chunked(filepath, lambda f: _transcribe_aliyun(f, keys), progress_cb)
        return text if not return_timestamps else (text, None)
    elif pid == 'baidu' or pid == 'baidu_builtin':
        text = _transcribe_baidu_chunked(filepath, keys, progress_cb)
        return text if not return_timestamps else (text, None)
    elif pid == 'groq_whisper':
        # Groq supports timestamps
        text, timestamps = _transcribe_with_ts_wrapper(filepath, keys['key'], 'groq', progress_cb)
        return text if not return_timestamps else (text, timestamps)
    elif pid == 'openai_whisper':
        # OpenAI supports timestamps
        text, timestamps = _transcribe_with_ts_wrapper(filepath, keys['key'], 'openai', progress_cb)
        return text if not return_timestamps else (text, timestamps)
    else:
        raise Exception(f'{pid} 转写暂未实现')

def _transcribe_with_ts_wrapper(filepath, api_key, provider, progress_cb=None):
    """Wrapper for transcribing with timestamps from Whisper APIs"""
    # Check if audio is long (> 55 seconds)
    import subprocess
    result = subprocess.run(['ffprobe', '-v', 'quiet', '-print_format', 'json', '-show_format', filepath],
        capture_output=True, text=True, creationflags=getattr(subprocess, 'CREATE_NO_WINDOW', 0))
    duration_s = float(json.loads(result.stdout).get('format', {}).get('duration', 0))

    if duration_s <= 55:
        # Short audio, transcribe directly with timestamps
        if provider == 'groq':
            return _transcribe_groq(filepath, api_key, return_timestamps=True)
        else:  # openai
            return _transcribe_whisper(filepath, api_key, return_timestamps=True)

    # Long audio - split into chunks and transcribe each with timestamps
    if progress_cb: progress_cb(f'长语音({int(duration_s)}秒)，正在分段转写...')
    tmpdir = tempfile.mkdtemp()
    chunk_pattern = os.path.join(tmpdir, 'chunk_%03d.wav')
    subprocess.run(['ffmpeg', '-i', filepath, '-f', 'segment', '-segment_time', '55',
        '-ac', '1', '-ar', '16000', '-y', chunk_pattern],
        capture_output=True, creationflags=getattr(subprocess, 'CREATE_NO_WINDOW', 0))

    chunks = sorted([os.path.join(tmpdir, f) for f in os.listdir(tmpdir) if f.startswith('chunk_')])
    if not chunks:
        raise Exception('音频分段失败')

    all_words = []
    all_text = ''
    time_offset = 0
    for i, chunk in enumerate(chunks):
        if progress_cb: progress_cb(f'转写分块 {i+1}/{len(chunks)}...')
        try:
            if provider == 'groq':
                text, words = _transcribe_groq(chunk, api_key, return_timestamps=True)
            else:  # openai
                text, words = _transcribe_whisper(chunk, api_key, return_timestamps=True)
            # Adjust timestamps with offset
            for w in words:
                w['start'] += time_offset
                w['end'] += time_offset
            all_words.extend(words)
            all_text += text
            # Update offset for next chunk (approximate based on audio duration)
            chunk_duration = (i + 1) * 55
            if i == len(chunks) - 1:
                chunk_duration = duration_s - (len(chunks) - 1) * 55
            time_offset += min(chunk_duration, 55)
        except Exception as e:
            # Continue with next chunk on error
            all_text += f'[{e}]'
        os.remove(chunk)

    os.rmdir(tmpdir)
    return all_text, all_words

