    if provider_id == 'funasr':
        try:
            _ensure_funasr_running()
            return True, '✓ FunASR服务运行中'
        except Exception as e:
            return False, f'FunASR启动失败: {str(e)[:60]}'
    elif provider_id == 'baidu_builtin':
        # Test builtin baidu keys
        try:
            resp = requests.post('https://aip.baidubce.com/oauth/2.0/token',
                params={'grant_type': 'client_credentials', 'client_id': BUILTIN_BAIDU_KEYS['key'], 'client_secret': BUILTIN_BAIDU_KEYS['secret']}, timeout=10)
            data = resp.json()
            if 'error' in data:
                return False, f'内置密钥失效: {data.get("error_description", data.get("error", ""))}'
            if data.get('access_token'):
                return True, '✓ 内置百度API连接成功'
            return False, '获取Token失败'
        except requests.exceptions.Timeout:
            return False, '连接超时，请检查网络'
        except requests.exceptions.ConnectionError:
            return False, '网络连接失败'
        except Exception as e:
            return False, f'连接失败: {e}'
    elif provider_id == 'aliyun':
        if not keys.get('key') or not keys.get('secret') or not keys.get('appKey'):
            return False, '请填写 AccessKey ID、Secret 和 AppKey'
        try:
            # Try to get token to validate credentials
            nonce = os.urandom(8).hex()
            ts = datetime.now(timezone.utc).strftime('%Y-%m-%dT%H:%M:%SZ')
            params = {
                'AccessKeyId': keys['key'], 'Action': 'CreateToken', 'Format': 'JSON',
                'RegionId': 'cn-shanghai', 'SignatureMethod': 'HMAC-SHA1',
                'SignatureNonce': nonce, 'SignatureVersion': '1.0',
                'Timestamp': ts, 'Version': '2019-02-28',
            }
            canon = '&'.join(f'{quote(k, safe="")}={quote(params[k], safe="")}' for k in sorted(params))
            sts = f'GET&{quote("/", safe="")}&{quote(canon, safe="")}'
            sig = base64.b64encode(hmac.new((keys['secret'] + '&').encode(), sts.encode(), hashlib.sha1).digest()).decode()
            params['Signature'] = sig
            query = '&'.join(f'{quote(k, safe="")}={quote(v, safe="")}' for k, v in params.items())
            resp = requests.get(f'https://nls-meta.cn-shanghai.aliyuncs.com/?{query}', timeout=10)
            if resp.json().get('Token', {}).get('Id'):
                return True, '✓ 阿里云API连接成功'
            return False, '阿里云认证失败: ' + resp.text[:60]
        except requests.exceptions.Timeout:
            return False, '连接超时，请检查网络'
        except requests.exceptions.ConnectionError:
            return False, '网络连接失败'
        except Exception as e:
            return False, f'连接失败: {str(e)[:60]}'
    elif provider_id == 'baidu':
        if not keys.get('key') or not keys.get('secret'):
            return False, '请填写 API Key 和 Secret Key'
        try:
            resp = requests.post('https://aip.baidubce.com/oauth/2.0/token',
                params={'grant_type': 'client_credentials', 'client_id': keys['key'], 'client_secret': keys['secret']}, timeout=10)
            data = resp.json()
            if 'error' in data:
                return False, f'百度认证失败: {data.get("error_description", data.get("error", ""))}'
            if data.get('access_token'):
                return True, '✓ 百度API连接成功'
            return False, '获取Token失败: ' + resp.text[:100]
        except requests.exceptions.Timeout:
            return False, '连接超时，请检查网络'
        except requests.exceptions.ConnectionError:
            return False, '网络连接失败'
        except Exception as e:
            return False, f'连接失败: {e}'
    elif provider_id == 'groq_whisper':
        api_key = keys.get('key', '')
        if not api_key:
            return False, '请填写 API Key'
        if not api_key.startswith('gsk_'):
            return False, 'Groq API Key 格式错误（应以 gsk_ 开头）'
        return True, '✓ Groq API Key 格式正确'
    elif provider_id == 'openai_whisper':
        api_key = keys.get('key', '')
        if not api_key:
            return False, '请填写 API Key'
        if not api_key.startswith('sk-'):
            return False, 'OpenAI API Key 格式错误（应以 sk- 开头）'
        return True, '✓ OpenAI API Key 格式正确'
    else:
        return True, '配置已保存，将在转写时验证'

